<?phpclass Bulan_model extends CI_Model {	    public function record_count() {        return $this->db->count_all('bulan');    }	public function getall() {		$query = $this->db->order_by('id', 'asc')->get('bulan');				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}	public function get($id) {		$query = $this->db->where('id', $id)->get('bulan', 1, 0);		if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}}